import time
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
import boto3

def take_screenshot(url):
    options = Options()
    options.headless = True
    driver = webdriver.Chrome(options=options)

    driver.get(url)
    time.sleep(2)  # Wait for elements to load

    screenshot = driver.get_screenshot_as_png()
    driver.quit()

    return screenshot

def upload_to_s3(screenshot, filename):
    s3 = boto3.client('s3')
    s3.put_object(Body=screenshot, Bucket='your_bucket_name', Key=filename)

def screenshot_service(url):
    screenshot = take_screenshot(url)
    filename = url.replace('https://', '').replace('http://', '') + '.png'
    upload_to_s3(screenshot, filename)

screenshot_service('http://example.com')